277→/// Parse an ISO 8601 timestamp string to unix seconds
278→fn parse_iso_timestamp(s: &str) -> Option<i64> {
279→    // Handle formats like "2026-03-16T21:10:30.808196Z" and "2026-03-16T21:10:30Z"
280→    let s = s.trim();
281→    // Strip fractional seconds and Z
282→    let s = s.trim_end_matches('Z');
283→    let s = if let Some(dot_pos) = s.rfind('.') {
284→        &s[..dot_pos]
285→    } else {
286→        s
287→    };
288→
289→    // Parse "YYYY-MM-DDTHH:MM:SS"
290→    let parts: Vec<&str> = s.split('T').collect();
291→    if parts.len() != 2 {
292→        return None;
293→    }
294→    let date_parts: Vec<i64> = parts[0].split('-').filter_map(|p| p.parse().ok()).collect();
295→    let time_parts: Vec<i64> = parts[1].split(':').filter_map(|p| p.parse().ok()).collect();
296→
297→    if date_parts.len() != 3 || time_parts.len() != 3 {
298→        return None;
299→    }
300→
301→    let (year, month, day) = (date_parts[0], date_parts[1], date_parts[2]);
302→    let (hour, min, sec) = (time_parts[0], time_parts[1], time_parts[2]);
303→
304→    // Simple days-since-epoch calculation (good enough for comparison)
305→    let mut days: i64 = 0;
306→    for y in 1970..year {
307→        days += if y % 4 == 0 && (y % 100 != 0 || y % 400 == 0) { 366 } else { 365 };
308→    }
309→    let month_days = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
310→    let is_leap = year % 4 == 0 && (year % 100 != 0 || year % 400 == 0);
311→    for m in 1..month {
312→        days += month_days[m as usize];
313→        if m == 2 && is_leap {
314→            days += 1;
315→        }
316→    }
317→    days += day - 1;
318→
319→    Some(days * 86400 + hour * 3600 + min * 60 + sec)
320→}
321→
322→fn count_transcript_steps(
323→    repo: &Repository,
324→    session_ref: &RawSessionRef,
325→    session_dir: &str,
326→) -> u32 {
327→    // Try to read the transcript file and count assistant messages (steps)
328→    // Paths from metadata may be absolute (leading /) — use as-is, stripping the /
329→    let transcript_path = session_ref
330→        .transcript
331→        .as_deref()
332→        .map(|t| {
333→            if t.starts_with('/') {
334→                t.trim_start_matches('/').to_string()
335→            } else {
336→                format!("{}{}", session_dir, t)
337→            }
338→        })
339→        .unwrap_or_else(|| format!("{}full.jsonl", session_dir));
340→
341→    if let Ok(content) = read_blob_from_tree(repo, &transcript_path) {
342→        session::read_transcript(&content)
343→            .into_iter()
344→            .filter(|message| message.role == "assistant")
345→            .count() as u32
346→    } else {
347→        0
348→    }
349→}
350→
351→fn read_blob_from_tree(repo: &Repository, path: &str) -> Result<String, String> {
352→    let branch_ref = repo
353→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
354→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
355→
356→    let commit = branch_ref
357→        .get()
358→        .peel_to_commit()
359→        .map_err(|e| format!("Failed to peel: {}", e))?;
360→
361→    let tree = commit
362→        .tree()
363→        .map_err(|e| format!("Failed to get tree: {}", e))?;
364→
365→    let entry = tree
366→        .get_path(std::path::Path::new(path))
367→        .map_err(|e| format!("Path not found: {}", e))?;
368→
369→    let blob = repo
370→        .find_blob(entry.id())
371→        .map_err(|e| format!("Failed to read blob: {}", e))?;
372→
373→    std::str::from_utf8(blob.content())
374→        .map(|s| s.to_string())
375→        .map_err(|e| format!("Invalid UTF-8: {}", e))
376→}
